mapper.select:
SELECT s.id, s.user_id AS userId, s.student_no AS studentNo, u.real_name AS realName, s.class_id AS classId, c.class_name AS className, m.major_name AS majorName, o.unit_name AS departmentName, u.avatar FROM students s LEFT JOIN users u ON s.user_id = u.id AND u.deleted = 0 LEFT JOIN classes c ON s.class_id = c.id AND c.deleted = 0 LEFT JOIN majors m ON s.major_id = m.id AND m.deleted = 0 LEFT JOIN org_units o ON c.org_unit_id = o.id AND dept.deleted = 0 WHERE s.deleted = 0 AND s.student_status = 1
AND s.class_id IN
#{cid}
AND ( u.real_name LIKE CONCAT('%', #{keyword}, '%') OR s.student_no LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY CASE WHEN u.real_name = #{keyword} THEN 0 WHEN u.real_name LIKE CONCAT(#{keyword}, '%') THEN 1 WHEN s.student_no = #{keyword} THEN 2 WHEN s.student_no LIKE CONCAT(#{keyword}, '%') THEN 3 ELSE 4 END, s.student_no ASC LIMIT #{limit}

